const input = $input.first().json;

const defaultQuestions = [
  'Master prompt co xac dinh ro audience, market/language va viewer intent khong?',
  'Master prompt co phan biet keyword intent voi viewer intent khong?',
  'Research pack co du bang chung de support cac claim trong master prompt khong?',
  'Master prompt co khoa duoc content format, viewer experience va mission khong?',
  'Subject type va subject topic co cu the, co can cu, va khong bi qua rong khong?',
  'Master prompt co bien research thanh content skeleton, script skeleton, scene split, image prompt va video prompt theo dung thu tu khong?',
  'Cac quy tac prompt anh co du subject details, environment lock, camera/lens va action cue khong?',
  'Cac quy tac prompt video co motion logic, action timing, consistency lock va audio/emotion cue khong?',
  'Co claim nao trong master prompt chua duoc nguon ho tro, dang suy luan qua muc, hoac can research them khong?',
  'Co contradiction nao giua master prompt, research pack, competitor analysis va content skeleton khong?',
  'Master prompt co rui ro ve IP, policy, factual accuracy, medical/finance/legal claim hoac hinh anh can do chinh xac cao khong?',
  'Prompt co tao du dieu kien de validate 1 tap/1 section mau truoc khi batch khong?',
  'Neu phai cho diem do chinh xac va san sang san xuat, diem 0-100 la bao nhieu va vi sao?',
  'Can sua phan nao trong master prompt truoc khi dung de sinh script/image/video prompt?'
];

let mcpBaseUrl = String(input.mcp_base_url || input.mcpUrl || 'http://127.0.0.1:3000/mcp').replace(/\/$/, '');
if (mcpBaseUrl.startsWith('http') && !mcpBaseUrl.endsWith('/mcp')) mcpBaseUrl = `${mcpBaseUrl}/mcp`;
if (!mcpBaseUrl.startsWith('http')) {
  throw new Error('mcp_base_url must be an HTTP URL, for example http://127.0.0.1:3000/mcp');
}

const sourceFormat = String(input.source_format || 'json');
const waitAfterUploadMs = Number(input.wait_after_upload_ms ?? 15000);
const showBrowser = input.show_browser === true || input.show_browser === 'true';

async function maybeReadFile(pathValue) {
  const filePath = String(pathValue || '').trim();
  if (!filePath) return '';

  try {
    const fs = await import('node:fs/promises');
    return await fs.readFile(filePath, 'utf8');
  } catch (error) {
    throw new Error(`Could not read file path "${filePath}". Pass the file content directly instead, or allow node:fs/promises in the n8n Code node. Original error: ${error.message}`);
  }
}

function parseQuestionPack(value, label) {
  if (!value) return [];
  let parsed = value;
  if (typeof value === 'string') {
    try {
      parsed = JSON.parse(value);
    } catch (error) {
      throw new Error(`${label} is not valid JSON: ${error.message}`);
    }
  }
  if (Array.isArray(parsed)) return parsed.map(String).filter(Boolean);
  if (Array.isArray(parsed.question)) return parsed.question.map(String).filter(Boolean);
  if (Array.isArray(parsed.questions)) return parsed.questions.map(String).filter(Boolean);
  throw new Error(`${label} must be an array or an object with question/questions array`);
}

function section(title, body) {
  const text = String(body || '').trim();
  return text ? `\n\n# ${title}\n${text}` : '';
}

const fileInputs = {
  masterPrompt: await maybeReadFile(input.master_prompt_path),
  researchPack: await maybeReadFile(input.research_pack_path),
  contentSkeleton: await maybeReadFile(input.content_skeleton_path),
  competitorAnalysis: await maybeReadFile(input.competitor_analysis_path),
  questionPack: await maybeReadFile(input.question_pack_path),
};

let questions = defaultQuestions;
if (input.question_pack_json || fileInputs.questionPack) {
  questions = parseQuestionPack(input.question_pack_json || fileInputs.questionPack, 'question_pack');
}

const sourceText = String(input.source_bundle || '').trim() || [
  section('MASTER PROMPT CAN VALIDATE', input.master_prompt || fileInputs.masterPrompt),
  section('RESEARCH PACK / SOURCE OF TRUTH', input.research_pack || fileInputs.researchPack),
  section('CONTENT SKELETON', input.content_skeleton || fileInputs.contentSkeleton),
  section('COMPETITOR ANALYSIS', input.competitor_analysis || fileInputs.competitorAnalysis),
  section('TRANSCRIPT / LESSON NOTES', input.transcript),
].join('').trim();

const sourceUrl = String(input.source_url || input.url || '').trim();
const shouldAddSource = input.add_source !== false && input.add_source !== 'false' && Boolean(sourceText || sourceUrl);

function notebookTarget(extra = {}) {
  const target = { ...extra };
  if (input.notebook_id) target.notebook_id = input.notebook_id;
  if (input.notebook_url) target.notebook_url = input.notebook_url;
  if (input.notebooklm_session_id) target.session_id = input.notebooklm_session_id;
  if (showBrowser) target.show_browser = true;
  return target;
}

function buildValidationPrompt() {
  const title = input.title ? `\nTen goi: ${input.title}` : '';
  const goal = input.validation_goal ? `\nMuc tieu validate: ${input.validation_goal}` : '';
  const numberedQuestions = questions.map((q, index) => `${index + 1}. ${q}`).join('\n');

  return [
    'Hay dong vai tro reviewer K07, dung NotebookLM de phan tich master prompt va validate do chinh xac dua tren cac nguon trong notebook.',
    'Tra loi bang tieng Viet. Phan biet ro: du kien co bang chung tu nguon, suy luan hop ly, va diem chua du nguon. Khong bia so lieu, case study, doi thu, hay ket luan neu nguon khong noi.',
    title + goal,
    '',
    'Bat buoc tra ve dung cac muc sau:',
    '1. Verdict: PASS / PARTIAL / FAIL, kem 1 doan ly do ngan.',
    '2. Accuracy score 0-100 va confidence Low/Medium/High.',
    '3. Evidence map: claim quan trong trong master prompt -> bang chung/citation -> trang thai Supported/Weak/Unsupported/Contradicted.',
    '4. Missing source list: nhung thong tin can nap them vao NotebookLM truoc khi ket luan chac.',
    '5. Research validation: audience, viewer intent, competitor pattern, format co view, comment insight, micro-niche gap, search intent vs viewer intent.',
    '6. Production validation: master prompt co du de di tiep sang script skeleton, scene split, image prompt, video prompt, QA gate va batch rule khong.',
    '7. Risk register: factual accuracy, IP/policy, topic too broad, AI visual feasibility, format drift, unsupported claim.',
    '8. Required fixes: sua truc tiep theo thu tu uu tien P0/P1/P2.',
    '9. Revised master prompt patch: chi viet cac block can them/sua, khong viet lai toan bo neu khong can.',
    '10. Next NotebookLM questions: 5-10 cau hoi tiep theo de lam sau neu chua du bang chung.',
    '',
    'Bo cau hoi validate:',
    numberedQuestions,
  ].join('\n');
}

function parseMcpHttpPayload(rawText, status) {
  const trimmed = rawText.trim();
  if (!trimmed) return null;

  try {
    return JSON.parse(trimmed);
  } catch {
    // Streamable HTTP may answer POST as server-sent events.
  }

  const dataLines = [];
  for (const line of trimmed.split(/\r?\n/)) {
    if (line.startsWith('data:')) dataLines.push(line.slice(5).trimStart());
  }

  if (dataLines.length > 0) {
    const data = dataLines.join('\n');
    try {
      return JSON.parse(data);
    } catch {
      throw new Error(`MCP returned invalid SSE JSON (${status}): ${data.slice(0, 500)}`);
    }
  }

  throw new Error(`MCP returned non-JSON response (${status}): ${rawText.slice(0, 500)}`);
}

async function rpc(body, mcpSessionId) {
  const headers = {
    accept: 'application/json, text/event-stream',
    'content-type': 'application/json',
  };
  if (mcpSessionId) headers['Mcp-Session-Id'] = mcpSessionId;

  const response = await fetch(mcpBaseUrl, {
    method: 'POST',
    headers,
    body: JSON.stringify(body),
  });

  const rawText = await response.text();
  const payload = parseMcpHttpPayload(rawText, response.status);

  if (!response.ok) {
    throw new Error(`MCP HTTP ${response.status}: ${rawText.slice(0, 500)}`);
  }

  if (payload?.error) {
    throw new Error(`MCP JSON-RPC error: ${JSON.stringify(payload.error)}`);
  }

  return { payload, headers: response.headers };
}

function parseToolResult(payload, toolName) {
  const textPart = payload?.result?.content?.find((part) => part.type === 'text');
  const text = textPart?.text;
  if (!text) return payload?.result ?? payload;

  let parsed = text;
  try {
    parsed = JSON.parse(text);
  } catch {
    return { text };
  }

  if (parsed?.success === false) {
    throw new Error(`${toolName} failed: ${parsed.error || JSON.stringify(parsed)}`);
  }

  return parsed?.data ?? parsed;
}

let mcpSessionId;
let sourceResult = null;
let askResult = null;
const validationPrompt = buildValidationPrompt();

try {
  const initialized = await rpc({
    jsonrpc: '2.0',
    id: 1,
    method: 'initialize',
    params: {
      protocolVersion: '2025-03-26',
      capabilities: {},
      clientInfo: { name: 'n8n-notebooklm-master-prompt-validation', version: '1.0.0' },
    },
  });

  mcpSessionId = initialized.headers.get('mcp-session-id');
  if (!mcpSessionId) {
    throw new Error('MCP initialize did not return Mcp-Session-Id header');
  }

  let rpcId = 2;
  async function callTool(name, args = {}) {
    const { payload } = await rpc({
      jsonrpc: '2.0',
      id: rpcId++,
      method: 'tools/call',
      params: { name, arguments: args },
    }, mcpSessionId);

    return parseToolResult(payload, name);
  }

  if (shouldAddSource) {
    const requestedType = String(input.source_type || '').toLowerCase();
    const type = requestedType === 'url' || (!sourceText && sourceUrl) ? 'url' : 'text';
    const content = type === 'url' ? sourceUrl : sourceText;

    if (!content) {
      throw new Error('No source content found. Provide master_prompt/source_bundle or source_url.');
    }

    sourceResult = await callTool('add_source', notebookTarget({
      type,
      content,
      title: input.title || input.source_title || (type === 'url' ? sourceUrl : `K07 master prompt validation ${new Date().toISOString()}`),
    }));

    if (waitAfterUploadMs > 0) {
      await new Promise((resolve) => setTimeout(resolve, waitAfterUploadMs));
    }
  }

  askResult = await callTool('ask_question', notebookTarget({
    question: validationPrompt,
    source_format: sourceFormat,
  }));

  return [{
    json: {
      ok: true,
      workflow: '18. Phan tich master prompt va validate do chinh xac bang NotebookLM',
      answer: askResult.answer,
      citations: askResult.sources || [],
      validation_prompt: validationPrompt,
      source_format: askResult.source_format || sourceFormat,
      notebook_url: askResult.notebook_url,
      notebooklm_session_id: askResult.session_id,
      source_added: sourceResult,
      questions_used: questions,
      provenance: askResult._provenance,
      raw: {
        ask: askResult,
      },
    },
  }];
} finally {
  if (mcpSessionId && input.keep_mcp_session !== true && input.keep_mcp_session !== 'true') {
    try {
      await fetch(mcpBaseUrl, { method: 'DELETE', headers: { 'Mcp-Session-Id': mcpSessionId } });
    } catch (error) {
      // Best-effort cleanup only.
    }
  }
}
